  const entries = fs.readdirSync(dir);
  return entries
    .filter(e => e.toLowerCase().endsWith('.pdf'))
    .map(e => path.join(dir, e));
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

