// Per-file processing
// ---------------------------------------------------------------------------

async function processFile(
  client: LlamaCloud,
  filePath: string,
  dataSchema: object,
): Promise<ResultEntry> {
  const fileName = path.basename(filePath);

  try {
    // 1. Upload file
